var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"왜, 왜 이래? 설마 함선이 추락하는 건 아니겠지?","JPN":"な、何？　まさか艦船が墜落するんじゃないよね？","ENG":"W-what's going on? The ship's not really going down, right?","TWN":"怎…怎麼會這樣？艦船不會真的迫降吧？"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"바닥이 기울어져.","JPN":"床が傾いてる。","ENG":"The floor is tilting.","TWN":"地板是傾斜的，"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"굴러 간다~","JPN":"転がる～","ENG":"I'm rolling awaaay.","TWN":"用滾的吧～"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"가긴 어딜 가! 이 바보야! 그러다 큰일나!","JPN":"どこ行くんだよ！　このバカ！　大怪我するかもしれないよ！","ENG":"What are you doing?! You're gonna hurt, you fool!","TWN":"是要滾去哪裡啦！你這個傻瓜！這樣會出事的！"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"감속 장치는 작동하는 것 같지만 가속도가 점점 붙고 있어.","JPN":"減速装置は作動してるみたいだけど、どんどん加速度が増してる。","ENG":"The decelerator seems to be working, but we're still gaining speed.","TWN":"雖然有啟動減速裝置，但速度卻越來越快。"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이 상태로 계속 가면 지면에 충돌할 때 우리 모두 도로시 다리 꼴이 날 거야.","JPN":"このままずっと行くと、地面に衝突する時にワタシたちもみんなドロシーの足のようになるはずだよ。","ENG":"At this rate, we're all going to end up like Dorothy's legs when it crashes into the ground.","TWN":"再這樣下去，撞到地面時，我們全都會像桃樂絲的腿一樣。"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"자기가 이렇게 만들어 놓았으면서 말은……! 그럼 어서 빠져나가야지!","JPN":"自分がやっておきながら……！　じゃあ、早く抜け出ないと！","ENG":"Wow... You did this to me, you know? Whatever, let's get out of here then!","TWN":"就是你把我弄成這樣的還敢講……！還是快離開這裡吧！"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"다들 무사해? 아직 함선에 있는 거지?","JPN":"みんな無事？　まだ艦船にいるんだよね？","ENG":"Is everyone okay? You’re still on the ship, right?","TWN":"大家都沒事吧？你們還在艦船裡嗎？"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"시그마! 헤론은 어떻게 됐어?","JPN":"シグマ！　ヘロンはどうなったの？","ENG":"Sigma! What happened to Heron?","TWN":"西格瑪！海倫怎麼樣？"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"완전히 넋이 나간 상태야. 아까부터 미친 듯이 웃고만 있어.","JPN":"完全に正気を失ってる。さっきからずっと狂ったように笑ってるんだ。","ENG":"She's gone insane. All she does is laugh like crazy.","TWN":"精神狀態不太好，從剛才就像發狂似地狂笑。"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"미안. 우리가 너무 늦었나 봐.","JPN":"ごめん。私たちが遅すぎたみたい。","ENG":"Sorry. I guess we were too late.","TWN":"對不起，我們好像晚了一步。"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"기운내. 네가 사과할 일이 아니야, 시그마.","JPN":"頑張って。シグマが謝ることじゃないよ。","ENG":"Chin up. You don't have to apologize to us, Sigma.","TWN":"打起精神來，這不是你的錯，西格瑪。"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"지금은 이 함선에서 탈출하는 게 먼저야. 탈출선이 있는 데로 가자.","JPN":"今はこの艦船から脱出するのが先だよ。脱出船のあるところに行こう。","ENG":"Getting off this ship is our number one priority. Let's head to the escape pods.","TWN":"現在最重要的是趕快逃離這艘艦船，先去有逃生船的地方吧！"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"사람들이 이렇게나 많은데…… 제때 탈 수 있을까?","JPN":"こんなに人が多いのに……乗れるのかな？","ENG":"But there are so many people here... Do you think we'll be able to get on one in time?","TWN":"人這麼多……搭得到嗎？"},"stage":{"bg":"COLOSSEUM","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"……저희가 안내해 드리겠습니다. 손님 여러분.","JPN":"……私たちがご案内いたします。お客様。","ENG":"Dear guests... We will guide you.","TWN":"……各位客人，我帶你們去吧。"},"stage":{"bg":"COLOSSEUM","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};